"use strict";
var BookStatus;
(function (BookStatus) {
    BookStatus[BookStatus["Available"] = 0] = "Available";
    BookStatus[BookStatus["CheckdOut"] = 1] = "CheckdOut";
    BookStatus[BookStatus["Reserved"] = 2] = "Reserved";
})(BookStatus || (BookStatus = {}));
let book1 = [
    "Harry Potter",
    "Jk Rowling",
    12345,
    BookStatus.Available
];
function borrowBook(book) {
    if (book[3] === BookStatus.Available) {
        book[3] = BookStatus.CheckdOut;
        return `${book[0]} borrowed successfully`;
    }
    else if (book[3] === BookStatus.Reserved) {
        return `${book[0]} is reserved`;
    }
    else {
        return `${book[0]} is already checked out`;
    }
}
console.log(borrowBook(book1));
console.log(book1);
//enum = fixed options  //0 1 2 auto numbering
